import { getManifest } from "@/lib/manifest";
import { ServiceGrid } from "@/components/ServiceGrid";
import { QuickActions } from "@/components/QuickActions";

const PHASE_ORDER = ["infrastructure", "1a", "1b", "1c", "2"];

const PHASE_SHORT: Record<string, string> = {
  infrastructure: "Infra",
  "1a": "1A",
  "1b": "1B",
  "1c": "1C",
  "2": "P2",
};

export default function StackPage() {
  const manifest = getManifest();
  const allServices = [...manifest.infrastructure, ...manifest.services];
  const essentialCount = allServices.filter((s) => s.verdict === "ESSENTIAL").length;
  const recommendedCount = allServices.filter((s) => s.verdict === "RECOMMENDED").length;
  const buildFromSrcCount = allServices.filter((s) => s.buildFromSource).length;
  const highRiskCount = allServices.filter((s) => s.riskLevel === "HIGH" || s.riskLevel === "MEDIUM").length;

  return (
    <div className="min-h-screen bg-gray-950 text-gray-100">
      <div className="max-w-screen-xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* Header */}
        <div className="mb-5">
          <h1 className="text-2xl font-bold tracking-tight text-white">Stack Overview</h1>
          <p className="mt-1 text-gray-500 text-sm">
            Hylono Stack v{manifest.meta.version} · read-only
          </p>
        </div>

        {/* Single compact summary strip */}
        <div className="bg-gray-900 border border-gray-800 rounded-xl px-4 py-3 mb-6">
          <div className="flex flex-wrap items-center gap-x-5 gap-y-2 text-sm">
            {/* Totals */}
            <span className="text-white font-semibold">{manifest.meta.totalServices} services</span>
            <span className="text-gray-600">·</span>
            <span className="text-green-400">{essentialCount} essential</span>
            <span className="text-gray-600">·</span>
            <span className="text-amber-400">{recommendedCount} recommended</span>
            <span className="text-gray-600">·</span>
            <span className="text-orange-400">{buildFromSrcCount} build-from-src</span>
            {highRiskCount > 0 && (
              <>
                <span className="text-gray-600">·</span>
                <span className="text-yellow-500">⚠ {highRiskCount} need extra setup</span>
              </>
            )}

            {/* Phase breakdown — right side */}
            <div className="ml-auto flex items-center gap-1.5 flex-wrap">
              {PHASE_ORDER.map((p) => {
                const count = allServices.filter((s) => s.phase === p).length;
                return (
                  <a
                    key={p}
                    href={`#phase-${p}`}
                    className="flex items-center gap-1 bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-gray-600 rounded-md px-2 py-0.5 transition-colors"
                  >
                    <span className="text-gray-400 text-xs font-medium">{PHASE_SHORT[p]}</span>
                    <span className="text-white text-xs font-bold">{count}</span>
                  </a>
                );
              })}
            </div>
          </div>
        </div>

        {/* Service grid with search/filter */}
        <ServiceGrid services={allServices} />

        {/* Integrations — collapsed by default */}
        <details className="mb-4 group">
          <summary className="flex items-center gap-2 cursor-pointer select-none py-3 border-b border-gray-800 text-sm text-gray-400 hover:text-gray-200 transition-colors list-none">
            <span className="text-gray-600 group-open:rotate-90 transition-transform inline-block">▶</span>
            Integration Flows
            <span className="text-gray-700 text-xs ml-1">({manifest.integrations.length})</span>
            <span className="ml-auto text-xs text-gray-700">automated data connections between services</span>
          </summary>
          <div className="overflow-x-auto rounded-xl border border-gray-800 mt-3">
            <table className="w-full text-sm text-left">
              <thead className="bg-gray-900 text-gray-600 uppercase text-xs tracking-wide">
                <tr>
                  <th className="px-4 py-3">From</th>
                  <th className="px-4 py-3">→ To</th>
                  <th className="px-4 py-3">What gets sent</th>
                  <th className="px-4 py-3">How</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-800">
                {manifest.integrations.map((flow, i) => (
                  <tr key={i} className="bg-gray-900 hover:bg-gray-800 transition-colors">
                    <td className="px-4 py-2 font-mono text-blue-400 text-xs">{flow.source}</td>
                    <td className="px-4 py-2 font-mono text-purple-400 text-xs">{flow.target}</td>
                    <td className="px-4 py-2 text-gray-300 text-xs">{flow.data}</td>
                    <td className="px-4 py-2 text-gray-500 text-xs">{flow.via}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </details>

        {/* R&D — collapsed by default */}
        <details className="mb-8 group">
          <summary className="flex items-center gap-2 cursor-pointer select-none py-3 border-b border-gray-800 text-sm text-gray-400 hover:text-gray-200 transition-colors list-none">
            <span className="text-gray-600 group-open:rotate-90 transition-transform inline-block">▶</span>
            R&amp;D References
            <span className="text-gray-700 text-xs ml-1">({manifest.rnd.length})</span>
            <span className="ml-auto text-xs text-gray-700">hardware &amp; firmware open-source projects</span>
          </summary>
          <div className="flex flex-col gap-1.5 mt-3">
            {manifest.rnd.map((item) => (
              <div key={item.id} className="bg-gray-900 border border-gray-800 rounded-lg px-4 py-2.5 flex items-center gap-4 hover:border-gray-700 transition-colors">
                <span className="font-semibold text-gray-200 text-sm w-36 flex-shrink-0">{item.name}</span>
                <span className="text-gray-500 text-xs flex-1">{item.description}</span>
                <a href={item.repository} target="_blank" rel="noopener noreferrer"
                  className="text-xs text-blue-400 hover:text-blue-300 transition-colors flex-shrink-0">
                  GitHub ↗
                </a>
              </div>
            ))}
          </div>
        </details>

        <footer className="text-center text-xs text-gray-700 pt-4 border-t border-gray-800">
          Hylono Stack Control Panel · v{manifest.meta.version} · {manifest.meta.totalServices} services · read-only
        </footer>
      </div>

      <QuickActions />
    </div>
  );
}
